"use client"

import * as React from 'react'
import { z } from "zod"
import { cn } from "@/lib/utils"
import { Button } from "@/registry/ts-UI/ui/button"
import { Input } from "@/registry/ts-UI/ui/input"
import { Label } from "@/registry/ts-UI/ui/label"
import {
    GlassCard,
    GlassCardHeader,
    GlassCardTitle,
    GlassCardDescription,
    GlassCardContent,
    GlassCardFooter
} from "@/registry/ts-UI/ui/glass-card"

const LoginSchema = z.object({
    username: z.string().min(1, "Username is required"),
    email: z.string().email("Invalid email address"),
    password: z.string().min(8, "Password must be at least 8 characters")
})

export const GlassLogin = () => {
    const [pending, setPending] = React.useState(false)
    const [state, setState] = React.useState({
        success: false,
        errors: {
            username: "",
            email: "",
            password: "",
        },
    })

    const handleSubmit = React.useCallback(
        async (e: React.FormEvent<HTMLFormElement>) => {
            e.preventDefault()
            setPending(true)

            const formData = new FormData(e.currentTarget)
            const data = Object.fromEntries(formData.entries())
            const result = LoginSchema.safeParse(data)

            if (!result.success) {
                const fieldErrors = result.error.flatten().fieldErrors
                setState({
                    success: false,
                    errors: {
                        username: fieldErrors.username?.[0] ?? "",
                        email: fieldErrors.email?.[0] ?? "",
                        password: fieldErrors.password?.[0] ?? "",
                    },
                })
                setPending(false)
                return
            }

            await new Promise((resolve) => setTimeout(resolve, 1500))
            setState({ success: true, errors: { username: "", email: "", password: "" } })
            setPending(false)
        },
        []
    )

    return (
            <GlassCard className="w-full max-w-md shadow-2xl">
                <GlassCardHeader>
                    <GlassCardTitle>Login</GlassCardTitle>
                    <GlassCardDescription>
                        Enter your credentials to access your account.
                    </GlassCardDescription>
                </GlassCardHeader>
                
                <form onSubmit={handleSubmit}>
                    <GlassCardContent className="space-y-4">
                        <div className="space-y-2">
                            <Label htmlFor="username" className="text-white/70">Username</Label>
                            <Input
                                id="username"
                                name="username"
                                placeholder="johndoe"
                                disabled={pending}
                            />
                            {state.errors.username && (
                                <p className="text-xs text-red-400/80">{state.errors.username}</p>
                            )}
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="email" className="text-white/70">Email</Label>
                            <Input
                                id="email"
                                name="email"
                                type="email"
                                placeholder="m@example.com"
                                disabled={pending}
                            />
                            {state.errors.email && (
                                <p className="text-xs text-red-400/80">{state.errors.email}</p>
                            )}
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="password" className="text-white/70">Password</Label>
                            <Input
                                id="password"
                                name="password"
                                type="password"
                                disabled={pending}
                            />
                            {state.errors.password && (
                                <p className="text-xs text-red-400/80">{state.errors.password}</p>
                            )}
                        </div>
                    </GlassCardContent>
                    
                    <GlassCardFooter className="mt-6">
                        <Button
                            type="submit"
                            disabled={pending}
                            className="w-full h-full rounded-lg flex items-center justify-center py-3 active:scale-95 transition-all duration-200 relative overflow-hidden border border-white/20 bg-gradient-to-b from-white/15 via-white/10 to-white/5 text-white backdrop-blur-md shadow-lg hover:scale-[1.02] hover:bg-white/10 hover:backdrop-blur-[25px] active:scale-[0.98] active:bg-white/5 before:absolute before:inset-0 before:bg-gradient-to-tr before:from-transparent before:via-white/5 before:to-transparent before:pointer-events-none"
                        >
                            {pending ? "Signing in..." : "Sign In"}
                        </Button>
                    </GlassCardFooter>
                </form>
            </GlassCard>
    )
}

import { cn } from "@/lib/utils"
import { cva } from "class-variance-authority"
import * as React from "react"

const GlassCardVariants=cva(
    "relative overflow-hidden flex flex-col gap-6 rounded-2xl border border-white/20 bg-gradient-to-br from-white/10 via-white/5 to-transparent text-white p-6 backdrop-blur-xl shadow-[0_8px_32px_0_rgba(0,0,0,0.37),inset_0_0_0_1px_rgba(255,255,255,0.1)] before:absolute before:inset-0 before:-z-10 before:bg-[radial-gradient(circle_at_50%_0%,rgba(255,255,255,0.1),transparent_70%)] after:absolute after:inset-0 after:-z-20 after:bg-black/20",
    {
        variants:{
            
        }

})
function GlassCard({className,children,...props}:React.ComponentProps<"div">){
    return (
        <div 
        data-slot="glass-card"
        className={cn(
            "relative overflow-hidden flex flex-col gap-6 rounded-2xl border border-white/20 bg-gradient-to-br from-white/10 via-white/5 to-transparent text-white p-6 backdrop-blur-xl shadow-[0_8px_32px_0_rgba(0,0,0,0.37),inset_0_0_0_1px_rgba(255,255,255,0.1)] before:absolute before:inset-0 before:-z-10 before:bg-[radial-gradient(circle_at_50%_0%,rgba(255,255,255,0.1),transparent_70%)] after:absolute after:inset-0 after:-z-20 after:bg-black/20",
            className
        )}{...props}>
          {children}
        </div>
    )
}

function GlassCardHeader({ className,...props}:React.ComponentProps<"div">){
    return(
        <div data-slot="glass-card-header"
        className={cn(
            "@container/card-header grid auto-rows-min grid-rows-[auto_auto] items-start gap-1.5 px-6 pb-6 border-b border-white/10 has-data-[slot=card-action]:grid-cols-[1fr_auto] relative after:absolute after:bottom-0 after:left-6 after:right-6 after:h-[1px] after:bg-gradient-to-r after:from-transparent after:via-white/20 after:to-transparent"
            ,className
        )}
        {...props}/>
    )
}

function GlassCardTitle({className,...props}:React.ComponentProps<"div">){
    return(
        <div
        data-slot="glass-card-title"
        className={cn("text-xl font-semibold leading-none tracking-tight text-white/90 drop-shadow-sm", 
            className )}{...props}/>
    )
}
function GlassCardDescription({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="glass-card-description"
      className={cn("text-sm text-white/50", className)}
      {...props}
    />
  )
}

function GlassCardContent({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="glass-card-content"
      className={cn("px-6", className)}
      {...props}
    />
  )
}

function GlassCardFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="glass-card-footer"
      className={cn("flex items-center px-6 pt-0", className)}
      {...props}
    />
  )
}

export { 
  GlassCard, 
  GlassCardHeader, 
  GlassCardTitle, 
  GlassCardDescription, 
  GlassCardContent, 
  GlassCardFooter 
}
